const bookChaptersMap: Record<number, { title: string; content: string }[]> = {
  1: [
    { title: "مقدمة التفسير", content: "بسم الله الرحمن الرحيم، الحمد لله رب العالمين، والصلاة والسلام على أشرف الأنبياء والمرسلين. هذا كتاب تفسير القرآن العظيم للإمام الحافظ عماد الدين أبي الفداء إسماعيل بن عمر بن كثير القرشي الدمشقي، المتوفى سنة 774 هجرية.\n\nيُعدّ هذا التفسير من أعظم التفاسير بالمأثور، حيث يعتمد المؤلف على تفسير القرآن بالقرآن، ثم بالسنة النبوية الشريفة، ثم بأقوال الصحابة والتابعين رضي الله عنهم أجمعين.\n\nوقد اشتهر هذا التفسير بين العلماء والطلاب لسهولة عبارته ووضوح منهجه، وهو من أكثر التفاسير انتشاراً في العالم الإسلامي." },
    { title: "سورة الفاتحة", content: "قال تعالى: ﴿بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ﴾. الاستعاذة قبل القراءة مشروعة بإجماع العلماء. وسورة الفاتحة هي أم القرآن وأم الكتاب والسبع المثاني والقرآن العظيم.\n\nوقد سُمّيت بالفاتحة لأنه يُفتتح بها القرآن الكريم، وهي أعظم سورة في القرآن كما ثبت في الحديث الصحيح. وفيها من المعاني الجليلة ما يشمل أصول الدين وفروعه.\n\nوفي هذه السورة العظيمة إثبات الحمد لله تعالى بجميع أنواعه، وإثبات ربوبيته للعالمين، ورحمته الواسعة، وملكه ليوم الدين." },
    { title: "سورة البقرة - الجزء الأول", content: "سورة البقرة هي أطول سور القرآن الكريم، نزلت بالمدينة المنورة، وآياتها مائتان وست وثمانون آية. وقد سُمّيت بهذا الاسم لاشتمالها على قصة البقرة التي أمر الله بني إسرائيل بذبحها.\n\nابتدأت السورة بالحروف المقطعة ﴿الم﴾ وقد اختلف العلماء في معناها اختلافاً كثيراً، والراجح أن هذه الحروف من المتشابه الذي استأثر الله بعلمه.\n\nثم ذكر الله تعالى صفات المتقين وصفات الكافرين وصفات المنافقين، وهذا من أبلغ ما جاء في القرآن في بيان أصناف الناس تجاه الهداية الربانية." },
    { title: "سورة البقرة - آية الكرسي", content: "قال تعالى: ﴿اللَّهُ لَا إِلَهَ إِلَّا هُوَ الْحَيُّ الْقَيُّومُ﴾. هذه آية الكرسي وهي أعظم آية في كتاب الله تعالى كما صح عن النبي صلى الله عليه وسلم.\n\nوفي هذه الآية العظيمة إثبات وحدانية الله تعالى في ألوهيته، وإثبات اسمين عظيمين من أسمائه الحسنى: الحي القيوم. فهو سبحانه الحي حياةً كاملة لم يسبقها عدم ولا يلحقها زوال.\n\nوقد ثبت في فضل هذه الآية أحاديث كثيرة، منها أن من قرأها في ليلة لم يزل عليه من الله حافظ ولا يقربه شيطان حتى يصبح." },
    { title: "سورة آل عمران", content: "سورة آل عمران مدنية، وآياتها مائتان آية. نزلت بعد سورة الأنفال، وتتناول موضوعات عقدية وتشريعية مهمة.\n\nافتُتحت السورة بالحروف المقطعة ﴿الم﴾ ثم بتقرير وحدانية الله تعالى وصفاته العليا. وفيها الحديث عن نزول الكتب السماوية وأنها من عند الله تعالى.\n\nومن أبرز موضوعاتها: قصة مريم عليها السلام وولادة عيسى عليه السلام، ومحاجة نصارى نجران، وغزوة أحد ودروسها وعبرها العظيمة." },
    { title: "سورة النساء", content: "سورة النساء من السور المدنية الطويلة، وآياتها مائة وست وسبعون آية. سُمّيت بذلك لكثرة ما ورد فيها من أحكام تتعلق بالنساء.\n\nابتدأت السورة بالأمر بتقوى الله تعالى وصلة الأرحام، ثم تناولت أحكام اليتامى والمواريث والنكاح وحقوق المرأة في الإسلام.\n\nوفي هذه السورة بيان شامل لأحكام الأسرة المسلمة، من حقوق الزوجين والأولاد، وأحكام المواريث التي فصّلها الله تعالى تفصيلاً دقيقاً لا مثيل له في أي شريعة أخرى." },
  ],
  2: [
    { title: "مقدمة جامع البيان", content: "بسم الله الرحمن الرحيم. هذا كتاب جامع البيان عن تأويل آي القرآن للإمام أبي جعفر محمد بن جرير الطبري، المتوفى سنة 310 هجرية.\n\nيُعدّ هذا التفسير أعظم التفاسير وأوسعها، وهو المرجع الأول لجميع المفسرين بعده. اعتمد فيه الطبري على جمع الروايات المسندة عن الصحابة والتابعين.\n\nومنهج الطبري في تفسيره أن يذكر الآية ثم يسوق الأقوال المختلفة في تفسيرها بأسانيده، ثم يرجح بينها بقواعد اللغة العربية وأصول التفسير." },
    { title: "القول في تأويل الاستعاذة", content: "اختلف أهل العلم في الاستعاذة: هل هي من القرآن أم لا؟ والصحيح أنها ليست من القرآن وإنما هي امتثال لأمر الله تعالى.\n\nوقد أمر الله تعالى بالاستعاذة عند القراءة فقال: ﴿فَإِذَا قَرَأْتَ الْقُرْآنَ فَاسْتَعِذْ بِاللَّهِ مِنَ الشَّيْطَانِ الرَّجِيمِ﴾.\n\nوالاستعاذة معناها: الالتجاء إلى الله تعالى والاعتصام به من شر الشيطان الرجيم الذي يصرف العبد عن تدبر كتاب الله تعالى." },
    { title: "تأويل سورة الفاتحة", content: "سورة فاتحة الكتاب، وهي مكية في قول أكثر أهل العلم. قال أبو جعفر: والصواب أنها مكية لأنها نزلت قبل الهجرة.\n\nوفي قوله تعالى ﴿الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ﴾ أي: الشكر لله خالصاً دون سائر ما يُعبد من دونه، ودون كل ما برأ من خلقه.\n\nوالعالمين: جمع عالَم، والعالَم: كل موجود سوى الله تعالى. فهو رب الإنس والجن والملائكة وسائر أصناف الخلق." },
    { title: "تأويل أوائل سورة البقرة", content: "القول في تأويل قوله تعالى: ﴿الم﴾. اختلف أهل التأويل في تأويل ذلك، فقال بعضهم: هو اسم من أسماء القرآن. وقال آخرون: هو اسم من أسماء الله تعالى.\n\nوقال آخرون: هي حروف مقطعة من أسماء وأفعال، كل حرف من ذلك استُغني به عن ذكر ما هو منه. والقول عندي في ذلك أن الله أعلم بمراده.\n\nثم قال تعالى: ﴿ذَلِكَ الْكِتَابُ لَا رَيْبَ فِيهِ هُدًى لِلْمُتَّقِينَ﴾ أي: هذا الكتاب الذي أنزلته إليك يا محمد لا شك فيه أنه من عند الله." },
    { title: "تأويل آيات الصيام", content: "قال تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا كُتِبَ عَلَيْكُمُ الصِّيَامُ كَمَا كُتِبَ عَلَى الَّذِينَ مِنْ قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ﴾.\n\nقال أبو جعفر: يعني بذلك جل ثناؤه: فُرض عليكم الصيام كما فرض على الذين من قبلكم من أهل الكتاب.\n\nوفي هذه الآيات بيان أحكام الصيام وآدابه، وأن الصيام شُرع لتحقيق التقوى في نفوس المؤمنين، وهي الغاية الكبرى من هذه العبادة العظيمة." },
    { title: "تأويل آيات الأحكام", content: "تناول الإمام الطبري آيات الأحكام بتوسع كبير، مبيناً أقوال الفقهاء والمجتهدين في استنباط الأحكام الشرعية من الآيات القرآنية.\n\nومن منهجه في ذلك أنه يذكر الآية ثم يبين ما فيها من أحكام، ويسوق أقوال العلماء بأسانيده، ثم يرجح ما يراه صواباً بالدليل.\n\nوهذا المنهج جعل تفسير الطبري مرجعاً أساسياً للفقهاء والأصوليين في فهم النصوص القرآنية واستنباط الأحكام منها." },
  ],
  3: [
    { title: "مقدمة المؤلف", content: "بسم الله الرحمن الرحيم. الحمد لله الذي من على عباده بإنزال كتابه الكريم، وجعله هدى ورحمة وشفاء لما في الصدور.\n\nهذا تفسير تيسير الكريم الرحمن في تفسير كلام المنان، للشيخ عبد الرحمن بن ناصر السعدي رحمه الله، المتوفى سنة 1376 هجرية.\n\nوقد سلك المؤلف فيه مسلك التيسير والإيضاح، فجاء تفسيراً واضح العبارة، سهل الأسلوب، يفهمه العامي والعالم على السواء." },
    { title: "تفسير سورة الفاتحة", content: "﴿بِسْمِ اللَّهِ الرَّحْمَنِ الرَّحِيمِ﴾ أي: أبتدئ بكل اسم لله تعالى، لأن لفظ الاسم مفرد مضاف فيعم جميع الأسماء الحسنى.\n\n﴿الْحَمْدُ لِلَّهِ رَبِّ الْعَالَمِينَ﴾ الحمد هو الثناء على المحمود بصفات الكمال وأفعال الجلال والجمال، وهو لله وحده لا شريك له.\n\nو﴿رَبِّ الْعَالَمِينَ﴾ هو المربي جميع العالمين بخلقهم وإعدادهم وتدبير أمورهم ونعمه عليهم التي لا تحصى." },
    { title: "تفسير أوائل سورة البقرة", content: "﴿الم﴾ تقدم أن هذه الحروف يقال فيها كما قال السلف: الله أعلم بمراده بذلك. ﴿ذَلِكَ الْكِتَابُ﴾ أي: هذا الكتاب العظيم.\n\n﴿لَا رَيْبَ فِيهِ﴾ لا شك ولا ارتياب فيه بوجه من الوجوه. ﴿هُدًى لِلْمُتَّقِينَ﴾ هداية ودلالة وإرشاد لمن اتقى الله تعالى.\n\nوالمتقون هم الذين اتقوا ما نهى الله عنه وأدوا ما أمر الله به، فهؤلاء هم الذين يهتدون بالقرآن وينتفعون به." },
    { title: "تفسير آيات التوحيد", content: "بيّن السعدي رحمه الله أن القرآن كله يدور حول التوحيد بأنواعه الثلاثة: توحيد الربوبية وتوحيد الألوهية وتوحيد الأسماء والصفات.\n\nوتوحيد الربوبية هو الإقرار بأن الله هو الخالق الرازق المدبر لجميع الأمور. وتوحيد الألوهية هو إفراد الله بالعبادة بجميع أنواعها.\n\nوقد أفاض السعدي في بيان هذه الأنواع وأدلتها من القرآن والسنة، مما جعل تفسيره مرجعاً مهماً في العقيدة الصحيحة." },
    { title: "تفسير آيات الأحكام", content: "تناول الشيخ السعدي آيات الأحكام بأسلوب ميسر وواضح، مبيناً الحكم الشرعي المستنبط من كل آية مع ذكر الحكمة منه.\n\nومن مميزات تفسيره في هذا الباب أنه يربط بين الأحكام الشرعية وحِكمها ومقاصدها، فيبين لماذا شرع الله هذا الحكم وما الفائدة المرجوة منه.\n\nوهذا المنهج يجعل القارئ يفهم الشريعة فهماً عميقاً ويستشعر عظمة التشريع الإسلامي وحكمته البالغة." },
  ],
  8: [
    { title: "كتاب بدء الوحي", content: "باب كيف كان بدء الوحي إلى رسول الله صلى الله عليه وسلم. حدثنا الحميدي عبد الله بن الزبير قال: حدثنا سفيان قال: حدثنا يحيى بن سعيد الأنصاري.\n\nعن محمد بن إبراهيم التيمي أنه سمع علقمة بن وقاص الليثي يقول: سمعت عمر بن الخطاب رضي الله عنه يقول: سمعت رسول الله صلى الله عليه وسلم يقول: إنما الأعمال بالنيات وإنما لكل امرئ ما نوى.\n\nوهذا الحديث أصل عظيم من أصول الإسلام، وقد بدأ به البخاري كتابه لأهميته في بيان أن الأعمال إنما تُقبل بحسب نية صاحبها." },
    { title: "كتاب الإيمان", content: "باب قول النبي صلى الله عليه وسلم: بُني الإسلام على خمس. وهي: شهادة أن لا إله إلا الله وأن محمداً رسول الله، وإقام الصلاة، وإيتاء الزكاة، والحج، وصوم رمضان.\n\nباب أمور الإيمان: عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: الإيمان بضع وستون شعبة، فأفضلها قول لا إله إلا الله، وأدناها إماطة الأذى عن الطريق، والحياء شعبة من الإيمان.\n\nوفي هذا الكتاب بيان حقيقة الإيمان وأركانه وشعبه، وأن الإيمان يزيد بالطاعة وينقص بالمعصية." },
    { title: "كتاب العلم", content: "باب فضل العلم. قال الله تعالى: ﴿يَرْفَعِ اللَّهُ الَّذِينَ آمَنُوا مِنْكُمْ وَالَّذِينَ أُوتُوا الْعِلْمَ دَرَجَاتٍ﴾.\n\nعن أنس بن مالك رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: طلب العلم فريضة على كل مسلم. وعن أبي هريرة رضي الله عنه: من سلك طريقاً يلتمس فيه علماً سهل الله له به طريقاً إلى الجنة.\n\nوقد جمع البخاري في هذا الكتاب الأحاديث المتعلقة بفضل العلم وآداب طلبه وأهمية نشره بين الناس." },
    { title: "كتاب الوضوء", content: "باب ما جاء في الوضوء. وقول الله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا إِذَا قُمْتُمْ إِلَى الصَّلَاةِ فَاغْسِلُوا وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى الْمَرَافِقِ﴾.\n\nعن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم توضأ مرة مرة. وفي رواية أخرى: توضأ مرتين مرتين، وفي رواية ثالثة: توضأ ثلاثاً ثلاثاً.\n\nوفي هذا الكتاب بيان أحكام الوضوء وفرائضه وسننه وآدابه، وما يبطل الوضوء وما لا يبطله." },
    { title: "كتاب الصلاة", content: "باب كيف فُرضت الصلاة في الإسراء. عن أنس بن مالك رضي الله عنه قال: فُرضت على النبي صلى الله عليه وسلم الصلوات ليلة أُسري به خمسين صلاة.\n\nثم نقصت حتى جُعلت خمساً، ثم نودي: يا محمد، إنه لا يُبدّل القول لدي، وإن لك بهذه الخمس خمسين.\n\nوفي هذا الكتاب جمع البخاري أحاديث الصلاة من حيث مواقيتها وأركانها وشروطها وسننها، وما يتعلق بصلاة الجماعة والجمعة والعيدين." },
    { title: "كتاب الزكاة", content: "باب وجوب الزكاة. وقول الله تعالى: ﴿وَأَقِيمُوا الصَّلَاةَ وَآتُوا الزَّكَاةَ﴾. عن ابن عباس رضي الله عنهما أن النبي صلى الله عليه وسلم بعث معاذاً إلى اليمن.\n\nفقال: إنك تأتي قوماً من أهل الكتاب فادعهم إلى شهادة أن لا إله إلا الله وأني رسول الله، فإن هم أطاعوك لذلك فأعلمهم أن الله افترض عليهم خمس صلوات.\n\nوفي هذا الكتاب بيان شامل لأحكام الزكاة: مقاديرها، وأنصبتها، ومصارفها، وشروط وجوبها، وأحكام زكاة الفطر." },
    { title: "كتاب الصوم", content: "باب وجوب صوم رمضان. وقول الله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا كُتِبَ عَلَيْكُمُ الصِّيَامُ كَمَا كُتِبَ عَلَى الَّذِينَ مِنْ قَبْلِكُمْ﴾.\n\nعن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: إذا جاء رمضان فُتّحت أبواب الجنة وغُلّقت أبواب النار وصُفّدت الشياطين.\n\nوجمع البخاري في هذا الكتاب الأحاديث المتعلقة بأحكام الصيام وآدابه وفضائله، وما يباح للصائم وما يبطل صومه." },
  ],
  9: [
    { title: "المقدمة", content: "بسم الله الرحمن الرحيم. هذا كتاب المسند الصحيح المختصر من السنن بنقل العدل عن العدل عن رسول الله صلى الله عليه وسلم، للإمام أبي الحسين مسلم بن الحجاج القشيري النيسابوري.\n\nيُعدّ صحيح مسلم ثاني أصح كتاب بعد صحيح البخاري، وقد اشترط فيه مسلم الصحة كما اشترطها البخاري.\n\nويتميز صحيح مسلم بحسن الترتيب وجمع طرق الحديث في مكان واحد، مما يسهل على الباحث الوقوف على جميع روايات الحديث." },
    { title: "كتاب الإيمان", content: "باب بيان الإيمان والإسلام والإحسان. عن عمر بن الخطاب رضي الله عنه قال: بينما نحن جلوس عند رسول الله صلى الله عليه وسلم إذ طلع علينا رجل شديد بياض الثياب.\n\nفسأله عن الإسلام والإيمان والإحسان وعلامات الساعة، وهذا الحديث يُعرف بحديث جبريل وهو من أعظم الأحاديث في بيان أصول الدين.\n\nوفي هذا الكتاب بيان حقيقة الإيمان وأنه قول وعمل، يزيد بالطاعة وينقص بالمعصية، وبيان شعب الإيمان المختلفة." },
    { title: "كتاب الطهارة", content: "باب وجوب الطهارة للصلاة. عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: لا يقبل الله صلاة أحدكم إذا أحدث حتى يتوضأ.\n\nوفي هذا الكتاب جمع الإمام مسلم الأحاديث المتعلقة بالطهارة: الوضوء والغسل والتيمم وإزالة النجاسة.\n\nومن أهم الأحاديث في هذا الباب حديث فضل الوضوء وأنه يكفر الذنوب، وحديث إسباغ الوضوء على المكاره." },
    { title: "كتاب الصلاة", content: "باب وجوب الصلوات الخمس. عن طلحة بن عبيد الله رضي الله عنه: أن أعرابياً جاء إلى رسول الله صلى الله عليه وسلم فقال: يا رسول الله، أخبرني ماذا فرض الله عليّ من الصلاة؟\n\nقال: الصلوات الخمس إلا أن تطّوع شيئاً. وفي هذا الحديث بيان أن الصلوات المفروضة خمس في اليوم والليلة.\n\nوقد جمع مسلم في هذا الكتاب أحاديث كثيرة في فضل الصلاة وأوقاتها وأركانها وسننها والخشوع فيها." },
    { title: "كتاب المساجد", content: "باب فضل بناء المساجد والحث عليه. عن عثمان بن عفان رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: من بنى مسجداً لله بنى الله له في الجنة مثله.\n\nوفي هذا الكتاب أحكام المساجد وآدابها وفضل الصلاة فيها، وأحكام المسجد الحرام والمسجد النبوي والمسجد الأقصى.\n\nومن الأحاديث المهمة في هذا الباب: النهي عن الشراء والبيع في المساجد، وفضل التبكير إلى الصلاة، وآداب المشي إلى المساجد." },
    { title: "كتاب الذكر والدعاء", content: "باب فضل الذكر والدعاء. عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: يقول الله تعالى: أنا عند ظن عبدي بي وأنا معه إذا ذكرني.\n\nفإن ذكرني في نفسه ذكرته في نفسي، وإن ذكرني في ملأ ذكرته في ملأ خير منهم. وهذا الحديث القدسي من أعظم الأحاديث في فضل الذكر.\n\nوجمع مسلم في هذا الكتاب أحاديث كثيرة في فضل الذكر والدعاء والاستغفار وأنواع الأذكار المستحبة في أوقاتها المختلفة." },
  ],
  16: [
    { title: "كتاب الإخلاص والنية", content: "باب الإخلاص وإحضار النية في جميع الأعمال. قال الله تعالى: ﴿وَمَا أُمِرُوا إِلَّا لِيَعْبُدُوا اللَّهَ مُخْلِصِينَ لَهُ الدِّينَ﴾.\n\nعن عمر بن الخطاب رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: إنما الأعمال بالنيات وإنما لكل امرئ ما نوى.\n\nوهذا الحديث أصل عظيم من أصول الإسلام، وعليه مدار الأعمال كلها، فلا يُقبل عمل إلا بنية صالحة خالصة لوجه الله تعالى." },
    { title: "كتاب التوبة", content: "باب الحث على التوبة والفرح بها. قال الله تعالى: ﴿وَتُوبُوا إِلَى اللَّهِ جَمِيعًا أَيُّهَ الْمُؤْمِنُونَ لَعَلَّكُمْ تُفْلِحُونَ﴾.\n\nعن أبي هريرة رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: والله إني لأستغفر الله وأتوب إليه في اليوم أكثر من سبعين مرة.\n\nوفي هذا الباب أحاديث كثيرة تبين سعة رحمة الله تعالى وقبوله لتوبة عبده مهما بلغت ذنوبه، وأن باب التوبة مفتوح ما لم تطلع الشمس من مغربها." },
    { title: "كتاب الصبر والشكر", content: "باب فضل الصبر والرضا بالقضاء. قال الله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا اصْبِرُوا وَصَابِرُوا وَرَابِطُوا وَاتَّقُوا اللَّهَ لَعَلَّكُمْ تُفْلِحُونَ﴾.\n\nعن أبي سعيد الخدري رضي الله عنه: أن ناساً من الأنصار سألوا رسول الله صلى الله عليه وسلم فأعطاهم، ثم سألوه فأعطاهم حتى نفد ما عنده.\n\nفقال: ما يكون عندي من خير فلن أدّخره عنكم، ومن يستعفف يعفه الله، ومن يستغن يغنه الله، ومن يتصبر يصبره الله، وما أُعطي أحد عطاء خيراً وأوسع من الصبر." },
    { title: "كتاب الصدق والتواضع", content: "باب الصدق والأمر به. قال الله تعالى: ﴿يَا أَيُّهَا الَّذِينَ آمَنُوا اتَّقُوا اللَّهَ وَكُونُوا مَعَ الصَّادِقِينَ﴾.\n\nعن عبد الله بن مسعود رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: عليكم بالصدق فإن الصدق يهدي إلى البر وإن البر يهدي إلى الجنة.\n\nوما يزال الرجل يصدق ويتحرى الصدق حتى يُكتب عند الله صديقاً. وإياكم والكذب فإن الكذب يهدي إلى الفجور وإن الفجور يهدي إلى النار." },
    { title: "كتاب بر الوالدين وصلة الأرحام", content: "باب فضل بر الوالدين وصلة الأرحام. عن أبي هريرة رضي الله عنه قال: جاء رجل إلى رسول الله صلى الله عليه وسلم فقال: يا رسول الله، من أحق الناس بحسن صحابتي؟\n\nقال: أمك. قال: ثم من؟ قال: أمك. قال: ثم من؟ قال: أمك. قال: ثم من؟ قال: أبوك. وفي هذا الحديث بيان عظيم لحق الأم في البر والإحسان.\n\nوجمع النووي في هذا الباب أحاديث كثيرة في فضل بر الوالدين وخطورة عقوقهما، وأن بر الوالدين من أعظم القربات إلى الله تعالى." },
    { title: "كتاب أذكار الصباح والمساء", content: "باب فضل الذكر. قال الله تعالى: ﴿فَاذْكُرُونِي أَذْكُرْكُمْ وَاشْكُرُوا لِي وَلَا تَكْفُرُونِ﴾.\n\nعن أبي هريرة رضي الله عنه أن رسول الله صلى الله عليه وسلم قال: من قال سبحان الله وبحمده في يوم مائة مرة حُطّت خطاياه ولو كانت مثل زبد البحر.\n\nوفي هذا الكتاب بيان لأذكار الصباح والمساء والأذكار بعد الصلوات وأذكار النوم والاستيقاظ وغيرها من الأذكار المسنونة." },
  ],
  17: [
    { title: "الحديث الأول: الأعمال بالنيات", content: "عن أمير المؤمنين أبي حفص عمر بن الخطاب رضي الله عنه قال: سمعت رسول الله صلى الله عليه وسلم يقول: إنما الأعمال بالنيات وإنما لكل امرئ ما نوى.\n\nفمن كانت هجرته إلى الله ورسوله فهجرته إلى الله ورسوله، ومن كانت هجرته لدنيا يصيبها أو امرأة ينكحها فهجرته إلى ما هاجر إليه.\n\nهذا الحديث أحد الأحاديث التي عليها مدار الإسلام، وقد قال الإمام الشافعي: يدخل هذا الحديث في سبعين باباً من أبواب الفقه." },
    { title: "الحديث الثاني: حديث جبريل", content: "عن عمر بن الخطاب رضي الله عنه قال: بينما نحن جلوس عند رسول الله صلى الله عليه وسلم ذات يوم إذ طلع علينا رجل شديد بياض الثياب شديد سواد الشعر.\n\nفسأله عن الإسلام فقال: أن تشهد أن لا إله إلا الله وأن محمداً رسول الله وتقيم الصلاة وتؤتي الزكاة وتصوم رمضان وتحج البيت.\n\nثم سأله عن الإيمان فقال: أن تؤمن بالله وملائكته وكتبه ورسله واليوم الآخر وتؤمن بالقدر خيره وشره. ثم سأله عن الإحسان فقال: أن تعبد الله كأنك تراه فإن لم تكن تراه فإنه يراك." },
    { title: "الحديث الثالث: أركان الإسلام", content: "عن أبي عبد الرحمن عبد الله بن عمر بن الخطاب رضي الله عنهما قال: سمعت رسول الله صلى الله عليه وسلم يقول: بُني الإسلام على خمس.\n\nشهادة أن لا إله إلا الله وأن محمداً رسول الله، وإقام الصلاة، وإيتاء الزكاة، وحج البيت، وصوم رمضان.\n\nوهذا الحديث بيان لأركان الإسلام الخمسة التي هي أساس الدين وقوامه، وبدونها لا يستقيم إسلام المرء." },
    { title: "الحديث السابع: الدين النصيحة", content: "عن أبي رقية تميم بن أوس الداري رضي الله عنه أن النبي صلى الله عليه وسلم قال: الدين النصيحة. قلنا: لمن؟\n\nقال: لله ولكتابه ولرسوله ولأئمة المسلمين وعامتهم. والنصيحة لله: الإيمان به وتعظيمه والإخلاص له في العبادة.\n\nوالنصيحة لكتابه: الإيمان بأنه كلام الله وتلاوته حق التلاوة والعمل بما فيه. والنصيحة لرسوله: الإيمان به واتباع سنته والدفاع عنه." },
    { title: "الحديث التاسع عشر: احفظ الله يحفظك", content: "عن أبي العباس عبد الله بن عباس رضي الله عنهما قال: كنت خلف النبي صلى الله عليه وسلم يوماً فقال: يا غلام إني أعلمك كلمات.\n\nاحفظ الله يحفظك، احفظ الله تجده تجاهك. إذا سألت فاسأل الله، وإذا استعنت فاستعن بالله.\n\nواعلم أن الأمة لو اجتمعت على أن ينفعوك بشيء لم ينفعوك إلا بشيء قد كتبه الله لك، ولو اجتمعوا على أن يضروك بشيء لم يضروك إلا بشيء قد كتبه الله عليك." },
    { title: "الحديث الخامس والعشرون: أبواب الخير", content: "عن أبي ذر رضي الله عنه أن ناساً من أصحاب رسول الله صلى الله عليه وسلم قالوا: يا رسول الله ذهب أهل الدثور بالأجور.\n\nيصلون كما نصلي ويصومون كما نصوم ويتصدقون بفضول أموالهم. قال: أو ليس قد جعل الله لكم ما تصّدقون؟ إن بكل تسبيحة صدقة.\n\nوكل تكبيرة صدقة وكل تحميدة صدقة وكل تهليلة صدقة، وأمر بالمعروف صدقة ونهي عن المنكر صدقة، وفي بُضع أحدكم صدقة." },
  ],
  26: [
    { title: "معنى التوحيد وفضله", content: "قال المؤلف رحمه الله: باب فضل التوحيد وما يكفر من الذنوب. وقول الله تعالى: ﴿الَّذِينَ آمَنُوا وَلَمْ يَلْبِسُوا إِيمَانَهُمْ بِظُلْمٍ أُولَئِكَ لَهُمُ الْأَمْنُ وَهُمْ مُهْتَدُونَ﴾.\n\nالتوحيد هو إفراد الله تعالى بالعبادة، وهو دعوة جميع الرسل عليهم السلام من أولهم إلى آخرهم.\n\nوفضل التوحيد عظيم، فهو سبب دخول الجنة والنجاة من النار، ومن حققه دخل الجنة بغير حساب ولا عذاب." },
    { title: "أنواع التوحيد", content: "التوحيد ينقسم إلى ثلاثة أنواع: توحيد الربوبية، وتوحيد الألوهية، وتوحيد الأسماء والصفات.\n\nتوحيد الربوبية: هو الإقرار بأن الله هو الخالق الرازق المحيي المميت المدبر لجميع الأمور. وهذا النوع أقر به المشركون ولم يدخلهم في الإسلام.\n\nتوحيد الألوهية: هو إفراد الله بالعبادة، وهو الذي وقع فيه الخلاف بين الرسل وأقوامهم. وهو المقصود الأعظم من دعوة الرسل." },
    { title: "نواقض التوحيد", content: "باب من الشرك لبس الحلقة والخيط ونحوهما لرفع البلاء أو دفعه. قال الله تعالى: ﴿قُلْ أَفَرَأَيْتُمْ مَا تَدْعُونَ مِنْ دُونِ اللَّهِ﴾.\n\nومن نواقض التوحيد: الشرك بأنواعه الأكبر والأصغر. فالشرك الأكبر مُخرج من الملة كعبادة غير الله والاستغاثة بغيره فيما لا يقدر عليه إلا الله.\n\nوالشرك الأصغر لا يُخرج من الملة ولكنه ينقص التوحيد كالرياء والحلف بغير الله وقول ما شاء الله وشئت." },
    { title: "باب الخوف من الشرك", content: "قال الله تعالى: ﴿إِنَّ اللَّهَ لَا يَغْفِرُ أَنْ يُشْرَكَ بِهِ وَيَغْفِرُ مَا دُونَ ذَلِكَ لِمَنْ يَشَاءُ﴾.\n\nعن إبراهيم عليه السلام أنه قال: ﴿وَاجْنُبْنِي وَبَنِيَّ أَنْ نَعْبُدَ الْأَصْنَامَ﴾. فإذا كان إبراهيم الخليل يخاف على نفسه الشرك فكيف بغيره؟\n\nوفي هذا الباب بيان خطورة الشرك وأن المسلم يجب أن يكون حذراً منه ويسأل الله السلامة والعافية من الوقوع فيه." },
    { title: "باب الدعاء إلى التوحيد", content: "قال الله تعالى: ﴿قُلْ هَذِهِ سَبِيلِي أَدْعُو إِلَى اللَّهِ عَلَى بَصِيرَةٍ أَنَا وَمَنِ اتَّبَعَنِي﴾.\n\nعن ابن عباس رضي الله عنهما أن رسول الله صلى الله عليه وسلم لما بعث معاذاً إلى اليمن قال له: إنك تأتي قوماً من أهل الكتاب فليكن أول ما تدعوهم إليه شهادة أن لا إله إلا الله.\n\nوفي هذا دليل على أن الدعوة إلى التوحيد هي أول واجبات الدعاة، وأنه يجب البدء بها قبل غيرها من أمور الدين." },
    { title: "باب تحقيق التوحيد", content: "قال الله تعالى: ﴿إِنَّ إِبْرَاهِيمَ كَانَ أُمَّةً قَانِتًا لِلَّهِ حَنِيفًا وَلَمْ يَكُ مِنَ الْمُشْرِكِينَ﴾.\n\nتحقيق التوحيد هو تخليصه من شوائب الشرك والبدعة والمعصية. ومن حقق التوحيد دخل الجنة بغير حساب ولا عذاب.\n\nوعن حصين بن عبد الرحمن قال: كنت عند سعيد بن جبير فقال: أيكم رأى الكوكب الذي انقض البارحة؟ فقال رجل: أنا. ثم قال: أما إني لم أكن في صلاة ولكني لُدغت." },
  ],
  31: [
    { title: "مقدمة الكتاب", content: "الحمد لله رب العالمين والصلاة والسلام على أشرف الأنبياء والمرسلين. هذا كتاب الرحيق المختوم للشيخ صفي الرحمن المباركفوري.\n\nفاز هذا الكتاب بالجائزة الأولى في مسابقة السيرة النبوية التي نظمتها رابطة العالم الإسلامي، وذلك لشموله ودقته وحسن عرضه.\n\nيتناول الكتاب سيرة النبي صلى الله عليه وسلم من مولده إلى وفاته بأسلوب سلس وعرض ممتع، معتمداً على المصادر الموثوقة." },
    { title: "نسب النبي ﷺ ومولده", content: "هو محمد بن عبد الله بن عبد المطلب بن هاشم بن عبد مناف بن قصي بن كلاب، أشرف الناس نسباً وأعلاهم حسباً.\n\nوُلد صلى الله عليه وسلم يوم الاثنين في شهر ربيع الأول من عام الفيل، الموافق عام 571 ميلادية.\n\nنشأ يتيماً فقد مات أبوه وهو في بطن أمه، ثم ماتت أمه آمنة بنت وهب وهو في السادسة من عمره، فكفله جده عبد المطلب ثم عمه أبو طالب." },
    { title: "بعثته ﷺ ونزول الوحي", content: "بُعث النبي صلى الله عليه وسلم على رأس أربعين سنة من عمره الشريف. وكان أول ما بُدئ به من الوحي الرؤيا الصالحة في النوم.\n\nثم جاءه الوحي وهو في غار حراء، فجاءه الملك جبريل عليه السلام وقال له: اقرأ. فقال: ما أنا بقارئ. فغطّه ثلاث مرات ثم قال: ﴿اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ﴾.\n\nفرجع النبي صلى الله عليه وسلم إلى خديجة رضي الله عنها يرجف فؤاده، فقالت له: كلا والله لا يخزيك الله أبداً، إنك لتصل الرحم وتحمل الكلّ وتكسب المعدوم." },
    { title: "الدعوة السرية والجهرية", content: "بدأ النبي صلى الله عليه وسلم بالدعوة سراً في أول الأمر، فدعا أقرب الناس إليه، فآمنت به خديجة وأبو بكر وعلي وزيد بن حارثة رضي الله عنهم.\n\nاستمرت الدعوة السرية ثلاث سنوات، ثم أمره الله بالجهر بالدعوة فقال: ﴿فَاصْدَعْ بِمَا تُؤْمَرُ وَأَعْرِضْ عَنِ الْمُشْرِكِينَ﴾.\n\nفواجه النبي صلى الله عليه وسلم أشد أنواع الأذى والاضطهاد من قريش، ولكنه صبر واحتسب وثبت على دعوته حتى نصره الله تعالى." },
    { title: "الهجرة إلى المدينة", content: "لما اشتد الأذى على المسلمين أذن الله لهم بالهجرة إلى المدينة المنورة. فهاجر المسلمون أفراداً وجماعات.\n\nثم هاجر النبي صلى الله عليه وسلم مع صاحبه أبي بكر الصديق رضي الله عنه، فمكثا في غار ثور ثلاث ليال ثم واصلا المسير.\n\nاستقبله أهل المدينة استقبالاً عظيماً بالأناشيد والفرح، وكان ذلك بداية مرحلة جديدة في تاريخ الإسلام، حيث أسس النبي صلى الله عليه وسلم الدولة الإسلامية." },
    { title: "الفتوحات والانتصارات", content: "بعد استقرار النبي صلى الله عليه وسلم في المدينة بدأت مرحلة الجهاد والفتوحات. وكانت غزوة بدر أول معركة كبرى في الإسلام.\n\nثم توالت الغزوات والسرايا، ومنها: غزوة أحد، وغزوة الخندق، وصلح الحديبية الذي كان فتحاً مبيناً.\n\nوتُوّجت هذه المرحلة بفتح مكة في السنة الثامنة للهجرة، حيث دخل الناس في دين الله أفواجاً، وتحقق وعد الله بنصر دينه وإعلاء كلمته." },
  ],
  40: [
    { title: "كتاب العلم", content: "بسم الله الرحمن الرحيم. الحمد لله الذي هدانا لهذا وما كنا لنهتدي لولا أن هدانا الله. هذا كتاب إحياء علوم الدين للإمام حجة الإسلام أبي حامد الغزالي.\n\nاعلم أن فضل العلم عظيم لا يُحاط به، فقد أمر الله نبيه بطلب الزيادة منه فقال: ﴿وَقُلْ رَبِّ زِدْنِي عِلْمًا﴾.\n\nوالعلوم تنقسم إلى: علوم شرعية وهي المحمودة، وعلوم دنيوية وهي على أقسام: منها ما هو محمود ومنها ما هو مذموم ومنها ما هو مباح." },
    { title: "كتاب قواعد العقائد", content: "اعلم أن العقيدة الصحيحة هي أساس الدين وعموده الذي يقوم عليه. وأول واجب على المكلف هو معرفة الله تعالى بأسمائه وصفاته.\n\nوأركان الإيمان ستة: الإيمان بالله وملائكته وكتبه ورسله واليوم الآخر والقدر خيره وشره.\n\nوقد بيّن الغزالي في هذا الكتاب أصول العقيدة الصحيحة بأسلوب يجمع بين العمق العلمي والوضوح في العرض." },
    { title: "كتاب أسرار الصلاة", content: "الصلاة عماد الدين ومفتاح الجنة، وهي صلة بين العبد وربه. وللصلاة ظاهر وباطن: فظاهرها الأركان والشروط، وباطنها الخشوع والحضور.\n\nوأول ما يُحاسب عليه العبد يوم القيامة الصلاة، فإن صلحت صلح سائر عمله وإن فسدت فسد سائر عمله.\n\nوقد بيّن الغزالي في هذا الكتاب أسرار الصلاة ومعانيها الروحية، وكيف يحقق المصلي الخشوع والحضور في صلاته." },
    { title: "كتاب أسرار الزكاة", content: "الزكاة ركن من أركان الإسلام، وهي حق المال الذي فرضه الله على الأغنياء للفقراء. وللزكاة حكم عظيمة منها: تطهير النفس من البخل.\n\nقال الله تعالى: ﴿خُذْ مِنْ أَمْوَالِهِمْ صَدَقَةً تُطَهِّرُهُمْ وَتُزَكِّيهِمْ بِهَا﴾. فالزكاة تطهير للمال والنفس معاً.\n\nوبيّن الغزالي أن الإنفاق في سبيل الله من أعظم أبواب التقرب إلى الله، وأن المال وسيلة لا غاية، والغاية هي رضا الله تعالى." },
    { title: "كتاب آداب الأكل", content: "للأكل آداب شرعية ينبغي للمسلم مراعاتها، منها: التسمية في أول الطعام، والحمد في آخره، والأكل مما يليه.\n\nوقد قال النبي صلى الله عليه وسلم: يا غلام سمّ الله وكل بيمينك وكل مما يليك. وهذه آداب جامعة في الأكل.\n\nوبيّن الغزالي أن المسلم ينبغي أن يكون معتدلاً في أكله، لا يسرف ولا يقتّر، وأن يجعل طعامه وسيلة للتقوي على طاعة الله." },
    { title: "كتاب ذم الدنيا", content: "اعلم أن الدنيا دار ممر لا دار مقر، وأنها مزرعة الآخرة. ومن أحبها واغتر بها فقد خسر خسراناً مبيناً.\n\nقال النبي صلى الله عليه وسلم: الدنيا سجن المؤمن وجنة الكافر. وقال: لو كانت الدنيا تعدل عند الله جناح بعوضة ما سقى كافراً منها شربة ماء.\n\nوليس المراد بذم الدنيا ترك العمل والكسب، بل المراد ذم التعلق بها والانشغال بها عن الآخرة." },
    { title: "كتاب التوبة", content: "التوبة واجبة على كل مسلم من كل ذنب صغيراً كان أو كبيراً. قال الله تعالى: ﴿وَتُوبُوا إِلَى اللَّهِ جَمِيعًا أَيُّهَ الْمُؤْمِنُونَ لَعَلَّكُمْ تُفْلِحُونَ﴾.\n\nوشروط التوبة ثلاثة: الإقلاع عن الذنب، والندم على ما فات، والعزم على عدم العود. وإن كان الذنب يتعلق بحق آدمي فلا بد من رد المظالم.\n\nوبيّن الغزالي أن باب التوبة مفتوح أبداً، وأن الله يفرح بتوبة عبده فرحاً عظيماً، وأن التوبة تجبّ ما قبلها." },
  ],
  41: [
    { title: "مقدمة منازل السائرين", content: "بسم الله الرحمن الرحيم. الحمد لله الذي جعل سلوك طريقه أفضل ما اشتغل به العبد، والصلاة والسلام على خير من سلك هذا الطريق.\n\nهذا كتاب مدارج السالكين بين منازل إياك نعبد وإياك نستعين، للإمام شمس الدين ابن قيم الجوزية رحمه الله.\n\nوهو شرح لكتاب منازل السائرين للإمام الهروي، وقد بيّن فيه ابن القيم منازل السلوك إلى الله تعالى ومراتب العبودية." },
    { title: "منزلة اليقظة", content: "أول منازل العبودية: اليقظة. وهي انتباه القلب من نومة الغفلة. قال الله تعالى: ﴿قُلْ إِنَّمَا أَعِظُكُمْ بِوَاحِدَةٍ أَنْ تَقُومُوا لِلَّهِ﴾.\n\nواليقظة هي أول خطوة في طريق السلوك إلى الله تعالى، فمن لم يستيقظ من غفلته لم يسلك الطريق أصلاً.\n\nوعلامة اليقظة: أن يشعر العبد بتقصيره في حق الله، ويعزم على الإصلاح والتوبة والإنابة إلى الله تعالى." },
    { title: "منزلة التوبة", content: "التوبة هي الرجوع إلى الله تعالى بعد الابتعاد عنه بالمعاصي والذنوب. وهي فريضة على كل مسلم في كل وقت.\n\nقال ابن القيم: التوبة هي حقيقة الدين كله. والتوبة هي أول المنازل وأوسطها وآخرها، فلا يفارقها العبد أبداً.\n\nوللتوبة ثلاث درجات: توبة العوام من الذنوب، وتوبة الخواص من الغفلة، وتوبة خواص الخواص من رؤية حسناتهم." },
    { title: "منزلة الصبر", content: "الصبر من أعظم منازل السالكين وأهمها. قال الله تعالى: ﴿إِنَّمَا يُوَفَّى الصَّابِرُونَ أَجْرَهُمْ بِغَيْرِ حِسَابٍ﴾.\n\nوالصبر ثلاثة أنواع: صبر على طاعة الله، وصبر عن معصية الله، وصبر على أقدار الله المؤلمة.\n\nوبيّن ابن القيم أن الصبر نصف الإيمان، فإن الإيمان صبر وشكر. ومن صبر على البلاء واحتسبه عند الله كان ذلك كفارة لذنوبه ورفعة في درجاته." },
    { title: "منزلة الشكر", content: "الشكر قرين الصبر في كتاب الله تعالى. قال تعالى: ﴿إِنَّ فِي ذَلِكَ لَآيَاتٍ لِكُلِّ صَبَّارٍ شَكُورٍ﴾.\n\nوحقيقة الشكر: الاعتراف بنعمة المنعم على وجه الخضوع. والشكر يكون بالقلب واللسان والجوارح.\n\nقال ابن القيم: الشكر مبني على خمس قواعد: خضوع الشاكر للمشكور، وحبه له، واعترافه بنعمته، وثناؤه عليه بها، وألا يستعملها فيما يكره." },
    { title: "منزلة المحبة", content: "المحبة هي أعظم المنازل وأجلها وأشرفها، وهي روح الإيمان والأعمال. قال الله تعالى: ﴿وَالَّذِينَ آمَنُوا أَشَدُّ حُبًّا لِلَّهِ﴾.\n\nوعلامة المحبة الصادقة: اتباع النبي صلى الله عليه وسلم، والإكثار من ذكر الله، والأنس بمناجاته، والشوق إلى لقائه.\n\nقال ابن القيم: من ادعى محبة الله ولم يتّبع رسوله فدعواه كاذبة حتى يتابع الرسول صلى الله عليه وسلم في جميع أقواله وأفعاله." },
  ],
};

function generateCategoryChapters(bookId: number, category: string, title: string, description: string): Chapter[] {
  const existing = bookChaptersMap[bookId];
  if (existing) {
    return existing.map((ch, i) => ({ id: i + 1, ...ch }));
  }

  const categoryChapters: Record<string, (t: string, d: string) => { title: string; content: string }[]> = {
    "القرآن الكريم وعلومه": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم، الحمد لله رب العالمين. هذا كتاب ${t}، ${d}.\n\nيُعدّ هذا الكتاب من أهم المصنفات في علوم القرآن الكريم، وقد بذل المؤلف جهداً كبيراً في جمع المادة العلمية وترتيبها وتحريرها.\n\nوهذا الكتاب نافع لطلاب العلم والباحثين في علوم القرآن، إذ يجمع بين العمق العلمي وسهولة العرض.` },
      { title: "منهج المؤلف في التفسير", content: `سلك المؤلف في كتابه منهجاً علمياً رصيناً، حيث اعتمد على المصادر الموثوقة والروايات الصحيحة في تفسير آيات القرآن الكريم.\n\nومن أهم ملامح هذا المنهج: تفسير القرآن بالقرآن أولاً، ثم بالسنة النبوية، ثم بأقوال الصحابة والتابعين.\n\nوقد تميز هذا المنهج بالدقة العلمية والأمانة في النقل والترجيح بين الأقوال المختلفة بالحجة والبرهان.` },
      { title: "أسباب النزول وأهميتها", content: `يُعدّ علم أسباب النزول من أهم علوم القرآن التي لا يستغني عنها المفسر. فمعرفة سبب نزول الآية تعين على فهم معناها فهماً صحيحاً.\n\nوقد قال الواحدي: لا يمكن معرفة تفسير الآية دون الوقوف على قصتها وبيان نزولها.\n\nوقد عُني العلماء بجمع أسباب النزول وتمحيصها، فألّفوا فيها مصنفات كثيرة تُعدّ مراجع أساسية في هذا العلم.` },
      { title: "الناسخ والمنسوخ", content: `النسخ في الاصطلاح هو رفع حكم شرعي بدليل شرعي متأخر عنه. وهو من المباحث المهمة في علوم القرآن.\n\nومعرفة الناسخ والمنسوخ ضرورية للفقيه والمجتهد، إذ لا يجوز الاستدلال بآية منسوخة على حكم شرعي.\n\nوقد اختلف العلماء في عدد الآيات المنسوخة، والراجح أنها قليلة جداً، وأكثر ما يُدّعى فيه النسخ هو من باب التخصيص أو التقييد.` },
      { title: "إعجاز القرآن الكريم", content: `القرآن الكريم معجزة الله الخالدة التي تحدى بها الإنس والجن أن يأتوا بمثلها. قال تعالى: ﴿قُلْ لَئِنِ اجْتَمَعَتِ الْإِنْسُ وَالْجِنُّ عَلَى أَنْ يَأْتُوا بِمِثْلِ هَذَا الْقُرْآنِ لَا يَأْتُونَ بِمِثْلِهِ﴾.\n\nوإعجاز القرآن متعدد الجوانب: إعجاز لغوي وبلاغي، وإعجاز تشريعي، وإعجاز علمي، وإعجاز غيبي.\n\nوكلما تقدم العلم وتطور ظهرت وجوه جديدة من إعجاز القرآن، مما يدل على أنه كلام الله الذي لا يأتيه الباطل من بين يديه ولا من خلفه.` },
    ],
    "الحديث النبوي": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم. الحمد لله رب العالمين. هذا كتاب ${t}، ${d}.\n\nويُعدّ هذا الكتاب من أهم مصادر السنة النبوية الشريفة، وقد حظي باهتمام العلماء والباحثين على مر العصور.\n\nوقد اعتنى المؤلف بانتقاء الأحاديث وترتيبها على الأبواب الفقهية تسهيلاً للباحث والقارئ.` },
      { title: "منهج المؤلف في التصنيف", content: `اتبع المؤلف منهجاً دقيقاً في جمع الأحاديث وترتيبها، حيث اشترط شروطاً في قبول الرواية تضمن صحة المادة المجموعة.\n\nومن أهم ملامح منهجه: العناية بالإسناد والتأكد من اتصاله، والتحقق من عدالة الرواة وضبطهم.\n\nوقد جاء ترتيب الكتاب على الأبواب الفقهية، مما يسهل الوصول إلى الأحاديث المطلوبة في كل باب.` },
      { title: "كتاب الطهارة", content: `باب ما جاء في الطهارة وأحكامها. الطهارة شرط لصحة الصلاة، وهي نوعان: طهارة من الحدث وطهارة من النجاسة.\n\nعن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: لا يقبل الله صلاة أحدكم إذا أحدث حتى يتوضأ.\n\nوفي هذا الباب بيان أحكام الوضوء والغسل والتيمم، وما يتعلق بالمياه وأحكامها، والنجاسات وكيفية إزالتها.` },
      { title: "كتاب الصلاة", content: `الصلاة أعظم أركان الإسلام بعد الشهادتين، وهي عمود الدين. فُرضت ليلة الإسراء والمعراج خمسين صلاة ثم خُففت إلى خمس.\n\nعن عبد الله بن مسعود رضي الله عنه قال: سألت النبي صلى الله عليه وسلم: أي العمل أحب إلى الله؟ قال: الصلاة على وقتها.\n\nوفي هذا الكتاب جمع المؤلف أحاديث الصلاة من مواقيتها وأركانها وشروطها وسننها ومبطلاتها.` },
      { title: "كتاب الجنائز", content: `باب ما جاء في الجنائز وأحكامها. عن أبي هريرة رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: أكثروا ذكر هاذم اللذات: الموت.\n\nومن أحكام الجنائز: تغسيل الميت وتكفينه والصلاة عليه ودفنه، وكل ذلك فرض كفاية على المسلمين.\n\nوقد بيّن المؤلف في هذا الكتاب أحكام الجنائز تفصيلاً مع ذكر الأحاديث الواردة في كل مسألة.` },
      { title: "كتاب البيوع والمعاملات", content: `باب ما جاء في البيوع وأحكامها. أحلّ الله البيع وحرّم الربا، والبيع أصله الحل والإباحة إلا ما نُهي عنه.\n\nعن حكيم بن حزام رضي الله عنه قال: قال رسول الله صلى الله عليه وسلم: البيّعان بالخيار ما لم يتفرقا، فإن صدقا وبيّنا بورك لهما في بيعهما.\n\nوفي هذا الكتاب بيان شامل لأحكام البيوع المباحة والمنهي عنها، وأحكام الربا والسلم والرهن وغيرها من المعاملات المالية.` },
    ],
    "الفقه الإسلامي": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم. الحمد لله الذي شرع لعباده أحكاماً تنظم حياتهم وتهديهم إلى الصراط المستقيم.\n\nهذا كتاب ${t}، ${d}.\n\nوقد اعتنى المؤلف ببيان الأحكام الفقهية بأدلتها من الكتاب والسنة، مع ذكر أقوال العلماء والترجيح بينها.` },
      { title: "كتاب الطهارة", content: `الطهارة في الاصطلاح: ارتفاع الحدث وما في معناه وزوال النجاسة. وهي شرط لصحة الصلاة والطواف ومس المصحف.\n\nوأقسام المياه ثلاثة: طهور وهو الباقي على خلقته، وطاهر غير مطهر وهو ما تغير بمخالط طاهر، ونجس وهو ما تغير بنجاسة.\n\nوفروض الوضوء ستة: غسل الوجه، وغسل اليدين إلى المرفقين، ومسح الرأس، وغسل الرجلين إلى الكعبين، والترتيب، والموالاة.` },
      { title: "كتاب الصلاة", content: `الصلاة لغة: الدعاء. واصطلاحاً: أقوال وأفعال مخصوصة مفتتحة بالتكبير مختتمة بالتسليم.\n\nوشروط الصلاة تسعة: الإسلام والعقل والتمييز ورفع الحدث وإزالة النجاسة وستر العورة ودخول الوقت واستقبال القبلة والنية.\n\nوأركان الصلاة أربعة عشر: القيام مع القدرة، وتكبيرة الإحرام، وقراءة الفاتحة، والركوع، والرفع منه، والسجود على الأعضاء السبعة، والاعتدال منه، والجلوس بين السجدتين، والتشهد الأخير، والجلوس له، والصلاة على النبي، والتسليمتان، والترتيب، والطمأنينة.` },
      { title: "كتاب الزكاة", content: `الزكاة ركن من أركان الإسلام وهي فرض على كل مسلم ملك نصاباً وحال عليه الحول.\n\nوالأموال التي تجب فيها الزكاة: الذهب والفضة والنقود، وعروض التجارة، والزروع والثمار، والأنعام.\n\nونصاب الذهب عشرون مثقالاً، ونصاب الفضة مائتا درهم، وفي كل منهما ربع العشر إذا حال الحول.` },
      { title: "كتاب الصيام", content: `الصيام لغة: الإمساك. واصطلاحاً: الإمساك عن المفطرات من طلوع الفجر الثاني إلى غروب الشمس مع النية.\n\nوشروط وجوب الصيام: الإسلام والبلوغ والعقل والقدرة عليه. ويجب صيام رمضان بأحد أمرين: رؤية الهلال أو إكمال شعبان ثلاثين يوماً.\n\nوالمفطرات: الأكل والشرب عمداً، والجماع في نهار رمضان، والقيء عمداً، والحجامة على خلاف بين العلماء.` },
      { title: "كتاب الحج والعمرة", content: `الحج ركن من أركان الإسلام، يجب على المستطيع مرة في العمر. قال تعالى: ﴿وَلِلَّهِ عَلَى النَّاسِ حِجُّ الْبَيْتِ مَنِ اسْتَطَاعَ إِلَيْهِ سَبِيلًا﴾.\n\nوأركان الحج أربعة: الإحرام، والوقوف بعرفة، وطواف الإفاضة، والسعي بين الصفا والمروة.\n\nوواجبات الحج: الإحرام من الميقات، والوقوف بعرفة إلى الليل، والمبيت بمزدلفة، والمبيت بمنى ليالي التشريق، ورمي الجمرات، والحلق أو التقصير، وطواف الوداع.` },
    ],
    "العقيدة": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم. الحمد لله الذي هدانا للإسلام وعلّمنا الإيمان ورزقنا العمل بالقرآن والسنة.\n\nهذا كتاب ${t}، ${d}.\n\nوعلم العقيدة هو أشرف العلوم وأجلها، لأنه يتعلق بمعرفة الله تعالى وأسمائه وصفاته، وما يجب على العبد تجاه ربه.` },
      { title: "أصول الإيمان", content: `الإيمان في اللغة: التصديق. وفي الاصطلاح: قول باللسان واعتقاد بالجنان وعمل بالأركان، يزيد بالطاعة وينقص بالمعصية.\n\nوأركان الإيمان ستة كما في حديث جبريل: الإيمان بالله وملائكته وكتبه ورسله واليوم الآخر والقدر خيره وشره.\n\nوالإيمان بالله يتضمن: الإيمان بوجوده، والإيمان بربوبيته، والإيمان بألوهيته، والإيمان بأسمائه وصفاته.` },
      { title: "توحيد الألوهية", content: `توحيد الألوهية هو إفراد الله تعالى بجميع أنواع العبادة الظاهرة والباطنة، قولاً وفعلاً ونفياً وإثباتاً.\n\nوهذا النوع من التوحيد هو الذي وقع فيه النزاع بين الرسل وأقوامهم، فالمشركون كانوا يقرون بتوحيد الربوبية لكنهم أشركوا في العبادة.\n\nقال الله تعالى: ﴿وَمَا أَرْسَلْنَا مِنْ قَبْلِكَ مِنْ رَسُولٍ إِلَّا نُوحِي إِلَيْهِ أَنَّهُ لَا إِلَهَ إِلَّا أَنَا فَاعْبُدُونِ﴾.` },
      { title: "الأسماء والصفات", content: `أهل السنة والجماعة يؤمنون بأسماء الله الحسنى وصفاته العلى كما وردت في الكتاب والسنة، من غير تحريف ولا تعطيل ومن غير تكييف ولا تمثيل.\n\nقال الله تعالى: ﴿لَيْسَ كَمِثْلِهِ شَيْءٌ وَهُوَ السَّمِيعُ الْبَصِيرُ﴾. ففي هذه الآية نفي المماثلة وإثبات الصفات.\n\nوقاعدة أهل السنة في هذا الباب: الإثبات بلا تمثيل، والتنزيه بلا تعطيل. فيثبتون لله ما أثبته لنفسه وما أثبته له رسوله صلى الله عليه وسلم.` },
      { title: "الإيمان باليوم الآخر", content: `الإيمان باليوم الآخر ركن من أركان الإيمان، ويشمل الإيمان بكل ما أخبر عنه الله ورسوله مما يكون بعد الموت.\n\nومن ذلك: فتنة القبر ونعيمه وعذابه، والبعث والنشور، والحساب والميزان، والصراط، والجنة والنار.\n\nوالإيمان باليوم الآخر يثمر في حياة المسلم ثمرات عظيمة: فهو يدفعه إلى العمل الصالح ويردعه عن المعاصي ويصبّره على مشاق الحياة.` },
      { title: "الإيمان بالقضاء والقدر", content: `الإيمان بالقدر يتضمن أربع مراتب: العلم والكتابة والمشيئة والخلق.\n\nفالله علم بكل شيء قبل أن يكون، وكتب ذلك في اللوح المحفوظ، وشاء وقوعه بمشيئته النافذة، وخلقه وأوجده.\n\nوالإيمان بالقدر لا ينافي الأسباب، فالله أمرنا بالأخذ بالأسباب مع التوكل عليه سبحانه. وما يصيب الإنسان من خير أو شر فبقدر الله تعالى.` },
    ],
    "السيرة والتاريخ": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم. الحمد لله رب العالمين، والصلاة والسلام على سيدنا محمد وعلى آله وصحبه أجمعين.\n\nهذا كتاب ${t}، ${d}.\n\nودراسة السيرة والتاريخ الإسلامي من أعظم العلوم نفعاً، فهي تعرّفنا بأحوال السابقين وتستخرج لنا العبر والدروس.` },
      { title: "العرب قبل الإسلام", content: `كانت جزيرة العرب قبل الإسلام تعيش في جاهلية جهلاء: عبادة أصنام وأوثان، ووأد للبنات، وسفك للدماء، وقطع للأرحام.\n\nوكانت القبائل العربية في حروب دائمة فيما بينها، لا يأمن أحدهم على نفسه وماله وعرضه.\n\nوقد بقيت بقايا من ملة إبراهيم عليه السلام في بعض العرب، كحج البيت وبعض مكارم الأخلاق، ولكنها كانت مشوبة بكثير من البدع والخرافات.` },
      { title: "بعثة النبي ﷺ", content: `بُعث النبي صلى الله عليه وسلم رحمة للعالمين، فأخرج الناس من الظلمات إلى النور، ومن عبادة العباد إلى عبادة رب العباد.\n\nكان عمره أربعين سنة حين جاءه الوحي في غار حراء، فنزل عليه جبريل بأول آيات القرآن: ﴿اقْرَأْ بِاسْمِ رَبِّكَ الَّذِي خَلَقَ﴾.\n\nفبدأ بالدعوة سراً ثلاث سنوات، ثم جهر بها، فواجه أشد أنواع المقاومة والإيذاء من قريش، لكنه صبر واحتسب حتى نصره الله.` },
      { title: "الهجرة وتأسيس الدولة", content: `لما اشتد إيذاء قريش للمسلمين أذن الله لهم بالهجرة إلى المدينة، وكانت الهجرة نقطة تحول في تاريخ الإسلام.\n\nوأول ما فعله النبي صلى الله عليه وسلم في المدينة: بناء المسجد النبوي، والمؤاخاة بين المهاجرين والأنصار، وكتابة الصحيفة مع اليهود.\n\nوبذلك أرسى النبي صلى الله عليه وسلم دعائم الدولة الإسلامية الأولى التي قامت على العدل والمساواة والشورى.` },
      { title: "الغزوات والفتوحات", content: `شرع الله الجهاد في المدينة دفاعاً عن الدين والمسلمين. وكانت غزوة بدر الكبرى أول لقاء عسكري بين المسلمين والمشركين.\n\nثم توالت الغزوات: أحد والخندق وخيبر وفتح مكة وحنين وتبوك. وفي كل غزوة دروس وعبر عظيمة.\n\nوقد انتهت هذه المرحلة بفتح مكة وانتشار الإسلام في الجزيرة العربية، ثم بعث النبي صلى الله عليه وسلم رسله إلى ملوك العالم يدعوهم إلى الإسلام.` },
      { title: "عصر الخلفاء الراشدين", content: `بعد وفاة النبي صلى الله عليه وسلم تولى الخلافة أبو بكر الصديق رضي الله عنه، ثم عمر بن الخطاب، ثم عثمان بن عفان، ثم علي بن أبي طالب رضي الله عنهم.\n\nوفي عهد الخلفاء الراشدين فُتحت بلاد فارس والشام ومصر وشمال أفريقيا، وانتشر الإسلام انتشاراً واسعاً.\n\nوقد تميز عصر الخلفاء الراشدين بالعدل والشورى والحكم بما أنزل الله، وكان مثالاً يُحتذى في الحكم الإسلامي.` },
    ],
    "اللغة العربية": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم. الحمد لله الذي أنزل كتابه بلسان عربي مبين، والصلاة والسلام على نبيه الأمين.\n\nهذا كتاب ${t}، ${d}.\n\nوعلم العربية من أشرف العلوم وأجلها، لأنه آلة فهم كتاب الله وسنة رسوله صلى الله عليه وسلم.` },
      { title: "أقسام الكلام", content: `الكلام في اصطلاح النحويين هو اللفظ المركب المفيد بالوضع. والكلمة: اسم وفعل وحرف.\n\nفالاسم: ما دل على معنى في نفسه ولم يقترن بزمان، كزيد وعمرو وكتاب. وعلاماته: الجر والتنوين والنداء وأل والإسناد إليه.\n\nوالفعل: ما دل على معنى في نفسه واقترن بزمان، كقام ويقوم وقم. والحرف: ما دل على معنى في غيره، كهل وفي ومن.` },
      { title: "المعرب والمبني", content: `المعرب: ما تغير آخره بسبب العوامل الداخلة عليه. والمبني: ما لزم آخره حالة واحدة.\n\nوالأصل في الأسماء الإعراب وفي الأفعال البناء. فالأسماء المبنية محصورة كالضمائر وأسماء الإشارة والأسماء الموصولة.\n\nوالإعراب أربعة أنواع: الرفع والنصب والجر والجزم. فالرفع والنصب يشتركان في الأسماء والأفعال، والجر خاص بالأسماء، والجزم خاص بالأفعال.` },
      { title: "المرفوعات", content: `المرفوعات سبعة: الفاعل ونائب الفاعل والمبتدأ والخبر واسم كان وخبر إن والتابع للمرفوع.\n\nالفاعل: هو الاسم المرفوع المذكور قبله فعله. نحو: قام زيدٌ. فزيدٌ: فاعل مرفوع بالضمة.\n\nوالمبتدأ: هو الاسم المرفوع العاري عن العوامل اللفظية. والخبر: هو المرفوع المسند إليه. نحو: زيدٌ قائمٌ.` },
      { title: "المنصوبات", content: `المنصوبات خمسة عشر: المفعول به، والمفعول المطلق، والمفعول فيه، والمفعول لأجله، والمفعول معه، والحال، والتمييز، والمستثنى، وخبر كان، واسم إن، والمنادى، ولا النافية للجنس، والتابع للمنصوب.\n\nالمفعول به: هو الاسم المنصوب الذي يقع عليه الفعل. نحو: ضربت زيداً. فزيداً: مفعول به منصوب بالفتحة.\n\nوالحال: هو الاسم المنصوب المفسر لما انبهم من الهيئات. نحو: جاء زيدٌ راكباً. فراكباً: حال منصوب.` },
      { title: "المجرورات", content: `المجرورات ثلاثة: المجرور بالحرف، والمجرور بالإضافة، والتابع للمجرور.\n\nحروف الجر هي: من، وإلى، وعن، وعلى، وفي، والباء، واللام، وغيرها. وهي تجر الأسماء بعدها.\n\nوالإضافة نسبة بين اسمين، يُسمى الأول مضافاً والثاني مضافاً إليه. نحو: كتاب الطالبِ. فالطالب: مضاف إليه مجرور بالكسرة.` },
    ],
    "الأخلاق والتزكية": (t, d) => [
      { title: `مقدمة ${t}`, content: `بسم الله الرحمن الرحيم. الحمد لله الذي بعث نبيه محمداً صلى الله عليه وسلم ليتمم مكارم الأخلاق.\n\nهذا كتاب ${t}، ${d}.\n\nوعلم الأخلاق والتزكية من أهم العلوم الشرعية، لأنه يُعنى بإصلاح القلب والنفس، وهما أساس صلاح العمل.` },
      { title: "فضل حسن الخلق", content: `حسن الخلق من أعظم ما يتقرب به العبد إلى الله تعالى. قال النبي صلى الله عليه وسلم: إن أحبكم إليّ وأقربكم مني مجلساً يوم القيامة أحاسنكم أخلاقاً.\n\nوقال صلى الله عليه وسلم: ما من شيء أثقل في ميزان المؤمن يوم القيامة من حسن الخلق، وإن الله يبغض الفاحش البذيء.\n\nوحسن الخلق يشمل: الصدق والأمانة والصبر والحلم والتواضع والعفو والإحسان والرحمة وغيرها من الصفات الحميدة.` },
      { title: "تزكية النفس", content: `تزكية النفس فريضة من فرائض الإسلام. قال الله تعالى: ﴿قَدْ أَفْلَحَ مَنْ زَكَّاهَا ۞ وَقَدْ خَابَ مَنْ دَسَّاهَا﴾.\n\nوالتزكية تعني: تطهير النفس من الأخلاق المذمومة كالكبر والعجب والحسد والرياء والغضب والبخل.\n\nوطريق التزكية: محاسبة النفس ومجاهدتها، والإكثار من ذكر الله والاستغفار، ومصاحبة الصالحين، وتعلم العلم النافع.` },
      { title: "أمراض القلوب وعلاجها", content: `القلب محل نظر الله تعالى، فإذا صلح صلح الجسد كله وإذا فسد فسد الجسد كله.\n\nومن أمراض القلوب: الكبر والعجب والحسد والرياء والحقد والغل والبخل والطمع وحب الدنيا.\n\nوعلاج هذه الأمراض يكون بمعرفة أسبابها ثم مجاهدة النفس على تركها، مع الاستعانة بالله تعالى والإلحاح في الدعاء وملازمة ذكر الله.` },
      { title: "الذكر والدعاء", content: `ذكر الله تعالى حياة القلوب ونورها. قال الله تعالى: ﴿أَلَا بِذِكْرِ اللَّهِ تَطْمَئِنُّ الْقُلُوبُ﴾.\n\nوالذكر أنواع: ذكر اللسان، وذكر القلب، وذكر الجوارح بالعمل الصالح. وأفضل الذكر: لا إله إلا الله.\n\nوالدعاء هو العبادة كما قال النبي صلى الله عليه وسلم. وآداب الدعاء: الإخلاص والخشوع والإلحاح، والبدء بالحمد والصلاة على النبي صلى الله عليه وسلم.` },
      { title: "الورع والزهد", content: `الورع هو ترك ما يُريب إلى ما لا يُريب. قال النبي صلى الله عليه وسلم: دع ما يريبك إلى ما لا يريبك.\n\nوالزهد في الدنيا ليس تركها بالكلية، وإنما هو عدم التعلق بها وجعلها وسيلة لا غاية.\n\nقال عمر بن عبد العزيز: الزهد في الدنيا ليس بتحريم الحلال ولا إضاعة المال، ولكنه أن تكون بما في يد الله أوثق منك بما في يدك.` },
    ],
  };

  const generator = categoryChapters[category];
  if (generator) {
    return generator(title, description).map((ch, i) => ({ id: i + 1, ...ch }));
  }

  return [
    { id: 1, title: `مقدمة ${title}`, content: `بسم الله الرحمن الرحيم. ${description}.\n\nيُعدّ هذا الكتاب من أهم المراجع في بابه، وقد لقي قبولاً واسعاً بين طلاب العلم والباحثين.\n\nوقد بذل المؤلف جهداً كبيراً في تأليف هذا الكتاب وترتيبه وتحريره.` },
    { id: 2, title: "المبحث الأول", content: `تناول المؤلف في هذا المبحث الأسس والقواعد التي بنى عليها كتابه، مع بيان المنهج الذي سار عليه.\n\nوقد اعتمد على المصادر الموثوقة والمراجع المعتبرة في تأليف هذا الكتاب.\n\nوجاء عرضه واضحاً وميسراً يسهل على القارئ فهمه والاستفادة منه.` },
    { id: 3, title: "المبحث الثاني", content: `في هذا المبحث توسع المؤلف في شرح الموضوعات الأساسية للكتاب، مع ذكر الأدلة والشواهد.\n\nوقد أحسن في ترتيب المادة العلمية وتقسيمها إلى فصول ومباحث تسهل على القارئ المتابعة.\n\nومن مميزات هذا الكتاب أنه يجمع بين العمق العلمي وسهولة الأسلوب.` },
    { id: 4, title: "المبحث الثالث", content: `واصل المؤلف في هذا المبحث عرض بقية الموضوعات المتعلقة بالكتاب، مع التفصيل في المسائل المهمة.\n\nوقد أضاف في هذا المبحث فوائد وتنبيهات مهمة لا يستغني عنها طالب العلم.\n\nوختم المبحث بخلاصة جامعة لأهم ما ورد فيه من نتائج وتوصيات.` },
    { id: 5, title: "الخاتمة والفوائد", content: `في ختام هذا الكتاب نلخص أهم الفوائد والنتائج التي توصلنا إليها.\n\nونسأل الله تعالى أن ينفع بهذا الكتاب وأن يجعله خالصاً لوجهه الكريم.\n\nوآخر دعوانا أن الحمد لله رب العالمين، والصلاة والسلام على نبينا محمد وعلى آله وصحبه أجمعين.` },
  ];
}

function getBookChapters(book: BookItem): Chapter[] {
  return generateCategoryChapters(book.id, book.category, book.title, book.description);
}

export default function LibraryPage() {
  const [searchQuery, setSearchQuery] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("الكل");
  const [selectedBook, setSelectedBook] = useState<BookItem | null>(null);
  const [activeChapter, setActiveChapter] = useState(0);
  const [bookmarks, setBookmarks] = useState<number[]>(() => {
    try {
      const saved = localStorage.getItem("library-bookmarks");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });
  const [readBooks, setReadBooks] = useState<number[]>(() => {
    try {
      const saved = localStorage.getItem("library-read-books");
      return saved ? JSON.parse(saved) : [];
    } catch { return []; }
  });
  const [sidebarOpen, setSidebarOpen] = useState(true);

  useEffect(() => {
    localStorage.setItem("library-bookmarks", JSON.stringify(bookmarks));
  }, [bookmarks]);

  useEffect(() => {
    localStorage.setItem("library-read-books", JSON.stringify(readBooks));
  }, [readBooks]);

  const toggleBookmark = useCallback((bookId: number, e?: React.MouseEvent) => {
    if (e) e.stopPropagation();
    setBookmarks(prev => prev.includes(bookId) ? prev.filter(id => id !== bookId) : [...prev, bookId]);
  }, []);

  const openBook = useCallback((book: BookItem) => {
    setSelectedBook(book);
    setActiveChapter(0);
    setSidebarOpen(true);
    if (!readBooks.includes(book.id)) {
      setReadBooks(prev => [...prev, book.id]);
    }
  }, [readBooks]);

  const closeReader = useCallback(() => {
    setSelectedBook(null);
    setActiveChapter(0);
  }, []);

  const filteredBooks = useMemo(() => {
    return books.filter((book) => {
      const matchesCategory = selectedCategory === "الكل" || book.category === selectedCategory;
      const matchesSearch =
        searchQuery === "" ||
        book.title.includes(searchQuery) ||
        book.author.includes(searchQuery);
      return matchesCategory && matchesSearch;
    });
  }, [searchQuery, selectedCategory]);

  const currentChapters = useMemo(() => {
    if (!selectedBook) return [];
    return getBookChapters(selectedBook);
  }, [selectedBook]);

  if (selectedBook) {
    const chapter = currentChapters[activeChapter];
    return (
      <div className="min-h-screen" style={{ background: "linear-gradient(135deg, #faf8f0 0%, #f5f0e8 100%)" }} data-testid="book-reader">
        <div className="sticky top-0 z-10 border-b" style={{ background: "linear-gradient(90deg, #1a5e3a 0%, #2d7a4f 50%, #1a5e3a 100%)", borderColor: "#c8a45e" }}>
          <div className="px-4 py-3 flex items-center justify-between">
            <div className="flex items-center gap-3">
              <Button
                data-testid="button-back-to-library"
                variant="ghost"
                size="sm"
                onClick={closeReader}
                className="text-white hover:bg-white/20 gap-2"
              >
                <ArrowRight className="w-4 h-4" />
                العودة للمكتبة
              </Button>
            </div>
            <div className="text-center flex-1">
              <h1 className="text-white font-serif text-lg font-bold" data-testid="reader-book-title">{selectedBook.title}</h1>
              <p className="text-white/70 text-sm">{selectedBook.author}</p>
            </div>
            <div className="flex items-center gap-2">
              <Button
                data-testid={`button-bookmark-reader-${selectedBook.id}`}
                variant="ghost"
                size="sm"
                onClick={() => toggleBookmark(selectedBook.id)}
                className="text-white hover:bg-white/20"
              >
                <Heart className={`w-5 h-5 ${bookmarks.includes(selectedBook.id) ? "fill-red-400 text-red-400" : ""}`} />
              </Button>
              <Button
                data-testid="button-toggle-sidebar"
                variant="ghost"
                size="sm"
                onClick={() => setSidebarOpen(!sidebarOpen)}
                className="text-white hover:bg-white/20 md:hidden"
              >
                <Book className="w-5 h-5" />
              </Button>
            </div>
          </div>
          <div className="h-1" style={{ background: "repeating-linear-gradient(90deg, #c8a45e 0px, #c8a45e 8px, transparent 8px, transparent 16px, #e8c96e 16px, #e8c96e 24px, transparent 24px, transparent 32px)" }} />
        </div>

        <div className="flex">
          <div
            className={`${sidebarOpen ? "w-72" : "w-0"} transition-all duration-300 overflow-hidden border-l flex-shrink-0`}
            style={{ borderColor: "#d4c5a0", background: "#faf6ee" }}
            data-testid="chapters-sidebar"
          >
            <div className="w-72">
              <div className="p-4 border-b" style={{ borderColor: "#d4c5a0" }}>
                <div className="relative mx-auto w-32 h-40 rounded-lg overflow-hidden mb-3" style={{ background: "linear-gradient(135deg, #1a5e3a, #2d7a4f)", boxShadow: "0 4px 12px rgba(0,0,0,0.15)" }}>
                  <div className="absolute inset-0 opacity-20" style={{ backgroundImage: "repeating-conic-gradient(#c8a45e 0% 25%, transparent 0% 50%)", backgroundSize: "20px 20px" }} />
                  <div className="absolute inset-0 flex flex-col items-center justify-center p-2 text-center">
                    <BookOpen className="w-8 h-8 text-[#c8a45e] mb-1" />
                    <span className="text-white text-xs font-serif leading-tight">{selectedBook.title}</span>
                  </div>
                  <div className="absolute bottom-0 left-0 right-0 h-6" style={{ background: "linear-gradient(to top, rgba(0,0,0,0.3), transparent)" }} />
                </div>
                <div className="text-center">
                  <Badge variant="outline" className="text-xs mb-1">{selectedBook.category}</Badge>
                  <p className="text-xs text-muted-foreground">{selectedBook.pages} صفحة</p>
                </div>
              </div>

              <div className="p-3">
                <h3 className="font-bold text-sm mb-2" style={{ color: "#1a5e3a" }}>📑 فهرس الكتاب</h3>
                <div className="space-y-1">
                  {currentChapters.map((ch, idx) => (
                    <button
                      key={ch.id}
                      data-testid={`button-chapter-${ch.id}`}
                      onClick={() => setActiveChapter(idx)}
                      className={`w-full text-right px-3 py-2 rounded-lg text-sm transition-all duration-200 ${
                        idx === activeChapter
                          ? "font-bold shadow-sm"
                          : "hover:bg-[#eee8d5]"
                      }`}
                      style={idx === activeChapter ? { background: "linear-gradient(90deg, #1a5e3a, #2d7a4f)", color: "white" } : {}}
                    >
                      {ch.title}
                    </button>
                  ))}
                </div>
              </div>
            </div>
          </div>

          <div className="flex-1 min-h-[calc(100vh-80px)]">
            <div className="max-w-3xl mx-auto p-6 md:p-10">
              <div className="mb-8">
                <div className="flex items-center gap-2 mb-2">
                  <span className="text-xs px-2 py-1 rounded" style={{ background: "#1a5e3a", color: "#c8a45e" }}>
                    الفصل {activeChapter + 1} من {currentChapters.length}
                  </span>
                </div>
                <h2 className="text-2xl md:text-3xl font-serif font-bold mb-1" style={{ color: "#1a3a2a" }} data-testid="reader-chapter-title">
                  {chapter?.title}
                </h2>
                <div className="h-0.5 w-24 rounded mt-2" style={{ background: "linear-gradient(90deg, #c8a45e, transparent)" }} />
              </div>

              <div
                className="prose prose-lg max-w-none leading-[2.2] text-lg"
                style={{ color: "#2a2a2a", fontFamily: "'Amiri', 'Traditional Arabic', serif" }}
                data-testid="reader-chapter-content"
              >
                {chapter?.content.split("\n\n").map((paragraph, pIdx) => (
                  <p key={pIdx} className="mb-6 text-justify" style={{ textIndent: "2em" }}>
                    {paragraph}
                  </p>
                ))}
              </div>

              <div className="mt-12 pt-6 border-t flex items-center justify-between" style={{ borderColor: "#d4c5a0" }}>
                <Button
                  data-testid="button-prev-chapter"
                  variant="outline"
                  size="sm"
                  disabled={activeChapter === 0}
                  onClick={() => setActiveChapter(prev => prev - 1)}
                  className="gap-2"
                >
                  <ChevronRight className="w-4 h-4" />
                  الفصل السابق
                </Button>
                <span className="text-sm text-muted-foreground">
                  {activeChapter + 1} / {currentChapters.length}
                </span>
                <Button
                  data-testid="button-next-chapter"
                  variant="outline"
                  size="sm"
                  disabled={activeChapter === currentChapters.length - 1}
                  onClick={() => setActiveChapter(prev => prev + 1)}
                  className="gap-2"
                >
                  الفصل التالي
                  <ChevronLeft className="w-4 h-4" />
                </Button>
              </div>
            </div>
          </div>
        </div>
      </div>
    );
  }

  return (
    <div className="p-6 space-y-6" data-testid="library-page">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-3xl font-bold font-serif text-primary" data-testid="library-title">المكتبة الإسلامية</h1>
          <p className="text-muted-foreground">مجموعة شاملة من أمهات الكتب والمراجع الإسلامية</p>
        </div>
        <div className="relative w-full md:w-96">
          <Search className="absolute right-3 top-3 h-4 w-4 text-muted-foreground" />
          <Input
            data-testid="input-search"
            placeholder="بحث بعنوان الكتاب أو المؤلف..."
            className="pr-10"
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
          />
        </div>
      </div>

      <div className="flex items-center gap-2 flex-wrap" data-testid="category-filters">
        <Filter className="h-4 w-4 text-muted-foreground ml-1" />
        {categories.map((cat) => (
          <Button
            key={cat}
            data-testid={`filter-category-${cat}`}
            variant={selectedCategory === cat ? "default" : "outline"}
            size="sm"
            className={selectedCategory === cat ? "bg-primary text-primary-foreground" : ""}
            onClick={() => setSelectedCategory(cat)}
          >
            {cat}
          </Button>
        ))}
      </div>

      <div className="flex items-center gap-2 text-sm text-muted-foreground" data-testid="books-count">
        <Book className="h-4 w-4" />
        <span>عرض {filteredBooks.length} من أصل {books.length} كتاب</span>
        {readBooks.length > 0 && (
          <span className="mr-4">• تمت قراءة {readBooks.length} كتاب</span>
        )}
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6" data-testid="books-grid">
        {filteredBooks.map((book) => (
          <Card
            key={book.id}
            data-testid={`card-book-${book.id}`}
            className="group hover:shadow-lg transition-all duration-300 border-primary/10 hover:border-primary/30 flex flex-col cursor-pointer"
            onClick={() => openBook(book)}
          >
            <CardHeader className="pb-3 relative flex-shrink-0">
              {book.featured && (
                <div className="absolute top-4 left-4">
                  <Badge variant="default" className="bg-accent text-accent-foreground" data-testid={`badge-featured-${book.id}`}>مميز</Badge>
                </div>
              )}
              <div className="absolute top-4 right-4">
                <button
                  data-testid={`button-bookmark-${book.id}`}
                  onClick={(e) => toggleBookmark(book.id, e)}
                  className="p-1 rounded-full hover:bg-muted transition-colors"
                >
                  <Heart className={`w-4 h-4 ${bookmarks.includes(book.id) ? "fill-red-500 text-red-500" : "text-muted-foreground"}`} />
                </button>
              </div>
              <div className="w-16 h-16 rounded-lg flex items-center justify-center mb-3 group-hover:scale-110 transition-transform duration-300 relative overflow-hidden" style={{ background: "linear-gradient(135deg, #1a5e3a, #2d7a4f)" }}>
                <div className="absolute inset-0 opacity-20" style={{ backgroundImage: "repeating-conic-gradient(#c8a45e 0% 25%, transparent 0% 50%)", backgroundSize: "10px 10px" }} />
                <Book className="w-8 h-8 text-[#c8a45e] relative z-10" />
              </div>
              <CardTitle className="font-serif text-xl leading-tight" data-testid={`text-book-title-${book.id}`}>{book.title}</CardTitle>
              <CardDescription data-testid={`text-book-author-${book.id}`}>{book.author}</CardDescription>
            </CardHeader>
            <CardContent className="flex-1">
              <p className="text-sm text-muted-foreground mb-3 line-clamp-2" data-testid={`text-book-desc-${book.id}`}>{book.description}</p>
              <div className="flex items-center gap-2 text-sm text-muted-foreground flex-wrap">
                <Badge variant="outline" className="text-xs font-normal">{book.category}</Badge>
                <span>• {book.pages} صفحة</span>
                {readBooks.includes(book.id) && (
                  <Badge variant="secondary" className="text-xs" data-testid={`badge-read-${book.id}`}>تمت القراءة</Badge>
                )}
              </div>
            </CardContent>
            <CardFooter className="flex-shrink-0">
              <Button
                data-testid={`button-browse-${book.id}`}
                className="w-full gap-2"
                style={{ background: "linear-gradient(90deg, #1a5e3a, #2d7a4f)", color: "white" }}
                onClick={(e) => { e.stopPropagation(); openBook(book); }}
              >
                <BookOpen className="w-4 h-4" />
                📖 قراءة الكتاب
              </Button>
            </CardFooter>
          </Card>
        ))}
      </div>

      {filteredBooks.length === 0 && (
        <div className="text-center py-16" data-testid="empty-results">
          <Book className="w-16 h-16 text-muted-foreground/30 mx-auto mb-4" />
          <p className="text-lg text-muted-foreground">لا توجد نتائج مطابقة للبحث</p>
          <p className="text-sm text-muted-foreground/70 mt-1">جرّب تغيير كلمات البحث أو اختيار تصنيف آخر</p>
        </div>
      )}
    </div>
  );
}